// === 天氣去重：每日只發送一次 ===
const staticData = $getWorkflowStaticData('global');
const taiwanNow = new Date(new Date().getTime() + 8 * 60 * 60 * 1000);
const todayStr = taiwanNow.toISOString().split('T')[0];
if (staticData.lastSentDate === todayStr) {
  console.log('今日天氣已發送，略過');
  return [];
}
staticData.lastSentDate = todayStr;

const data = $input.first().json;
const current = data.current;
const daily = data.daily;

const weatherCodes = {
  0: '☀️ 晴天',
  1: '🌤️ 大致晴朗',
  2: '⛅ 局部多雲',
  3: '☁️ 陰天',
  45: '🌫️ 霧',
  48: '🌫️ 霧淞',
  51: '🌦️ 輕微毛毛雨',
  53: '🌦️ 毛毛雨',
  55: '🌦️ 濃密毛毛雨',
  61: '🌧️ 小雨',
  63: '🌧️ 中雨',
  65: '🌧️ 大雨',
  71: '🌨️ 小雪',
  73: '🌨️ 中雪',
  75: '🌨️ 大雪',
  80: '🌦️ 陣雨',
  81: '🌧️ 中陣雨',
  82: '⛈️ 大陣雨',
  95: '⛈️ 雷暴',
  96: '⛈️ 雷暴伴冰雹',
  99: '⛈️ 強雷暴伴冰雹',
};

const fmt = (code) => weatherCodes[code] || `代碼 ${code}`;

const toDate = (str) => new Date(str).toLocaleDateString('zh-TW', {
  timeZone: 'Asia/Taipei',
  month: 'long',
  day: 'numeric',
  weekday: 'long'
});

const todaySection = [
  '## 📅 今天　' + toDate(daily.time[0]),
  `> ${fmt(daily.weather_code[0])}`,
  `> 🌡️ 現在：**${current.temperature_2m}°C**　體感 ${current.apparent_temperature}°C`,
  `> 📊 高低溫：${daily.temperature_2m_max[0]}°C / ${daily.temperature_2m_min[0]}°C`,
  `> 🌧️ 降雨機率：${daily.precipitation_probability_max[0]}%`,
  `> 💧 濕度：${current.relative_humidity_2m}%　💨 風速：${current.wind_speed_10m} km/h`,
].join('\n');

const tomorrowSection = [
  '## 📅 明天　' + toDate(daily.time[1]),
  `> ${fmt(daily.weather_code[1])}`,
  `> 📊 高低溫：${daily.temperature_2m_max[1]}°C / ${daily.temperature_2m_min[1]}°C`,
  `> 🌧️ 降雨機率：${daily.precipitation_probability_max[1]}%`,
].join('\n');

const message = [
  '# 🌏 台北市士林區 天氣預報',
  '',
  todaySection,
  '',
  tomorrowSection,
].join('\n');

return [{ json: { content: message } }];
